import React, { useState, useEffect, useCallback } from 'react';
import { Container, Card, Form, Row, Col, Button, Alert, Table, Badge, Spinner } from 'react-bootstrap';

const API_BASE = 'https://hostel-management-backend-eo9s.onrender.com/api';

/* ================= FINAL UI FIX ================= */
const styles = `
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700;800&display=swap');

body {
  background: #060b1a !important;
}

/* MAIN */
.complaints-container {
  font-family: 'Inter', sans-serif;
  min-height: 100vh;
  color: #f1f5f9;
}

/* CARD */
.card {
  background: rgba(20,18,50,0.9) !important;
  border: 1px solid rgba(255,255,255,0.1) !important;
  border-radius: 18px !important;
  color: white !important;
}

/* HEADER */
.card-header {
  background: transparent !important;
  border-bottom: 1px solid rgba(255,255,255,0.1) !important;
}

/* ===== TEXT VISIBILITY FIX (MAIN PART) ===== */
input, textarea, select {
  background: rgba(255,255,255,0.08) !important;
  color: #ffffff !important;
  -webkit-text-fill-color: #ffffff !important;
  border: 1px solid rgba(255,255,255,0.25) !important;
}

input:focus, textarea:focus, select:focus {
  color: #ffffff !important;
  -webkit-text-fill-color: #ffffff !important;
  background: rgba(255,255,255,0.12) !important;
  outline: none !important;
  box-shadow: none !important;
}

/* Placeholder */
::placeholder {
  color: #cbd5e1 !important;
  opacity: 1 !important;
}

/* Label */
.form-label {
  color: #e2e8f0 !important;
  font-weight: 600;
}

/* BUTTON */
.btn-primary {
  background: linear-gradient(135deg,#8b5cf6,#ec4899);
  border: none;
  font-weight: 600;
}

/* TABLE */
.table {
  color: white !important;
}

.table thead {
  background: rgba(139,92,246,0.2) !important;
}

.table td, .table th {
  background: transparent !important;
  color: white !important;
}

.table tbody tr:hover {
  background: rgba(255,255,255,0.05);
}

/* BADGE */
.badge {
  border-radius: 20px;
  padding: 6px 10px;
}

/* ALERT */
.alert {
  color: white !important;
}
`;

const StudentComplaint = () => {
  const [formData, setFormData] = useState({
    category: '',
    subject: '',
    description: ''
  });

  const [submitStatus, setSubmitStatus] = useState({
    show: false,
    message: '',
    variant: ''
  });

  const [complaints, setComplaints] = useState([]);
  const [loadingComplaints, setLoadingComplaints] = useState(true);
  const [loadingSubmit, setLoadingSubmit] = useState(false);

  const student = JSON.parse(localStorage.getItem('student') || '{}');

  const fetchComplaints = useCallback(async () => {
    if (!student.rollNo) return;

    try {
      setLoadingComplaints(true);
      const res = await fetch(`${API_BASE}/complaints?rollno=${student.rollNo}`);
      const data = await res.json();
      setComplaints(data.reverse());
    } finally {
      setLoadingComplaints(false);
    }
  }, [student.rollNo]);

  useEffect(() => {
    fetchComplaints();
  }, [fetchComplaints]);

  const handleChange = (e) => {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.category || !formData.subject || !formData.description) {
      setSubmitStatus({
        show: true,
        message: "Please fill all fields",
        variant: "danger"
      });
      return;
    }

    try {
      setLoadingSubmit(true);

      await fetch(`${API_BASE}/complaints`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...formData,
          name: student.name,
          rollno: student.rollNo
        })
      });

      setSubmitStatus({
        show: true,
        message: "Complaint submitted successfully!",
        variant: "success"
      });

      setFormData({
        category: '',
        subject: '',
        description: ''
      });

      fetchComplaints();

    } catch {
      setSubmitStatus({
        show: true,
        message: "Submission failed",
        variant: "danger"
      });
    } finally {
      setLoadingSubmit(false);
    }
  };

  const getStatusBadge = (status) => {
    switch ((status || 'pending').toLowerCase()) {
      case 'resolved':
        return <Badge bg="success">Resolved</Badge>;
      case 'in-progress':
        return <Badge bg="info">In Progress</Badge>;
      default:
        return <Badge bg="warning">Pending</Badge>;
    }
  };

  return (
    <>
      <style>{styles}</style>

      <Container className="py-4 complaints-container">

        {/* FORM */}
        <Card className="mb-4">
          <Card.Header>
            <h4>📢 Submit Complaint</h4>
          </Card.Header>

          <Card.Body>

            {submitStatus.show && (
              <Alert variant={submitStatus.variant}>
                {submitStatus.message}
              </Alert>
            )}

            <Form onSubmit={handleSubmit}>

              <Row className="mb-3">
                <Col md={6}>
                  <Form.Label>Category</Form.Label>
                  <Form.Select
                    name="category"
                    value={formData.category}
                    onChange={handleChange}
                  >
                    <option value="">Select Category</option>
                    <option>Maintenance</option>
                    <option>Electrical</option>
                    <option>Cleanliness</option>
                  </Form.Select>
                </Col>

                <Col md={6}>
                  <Form.Label>Subject</Form.Label>
                  <Form.Control
                    type="text"
                    name="subject"
                    value={formData.subject}
                    onChange={handleChange}
                    placeholder="Enter subject"
                  />
                </Col>
              </Row>

              <Form.Label>Description</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                name="description"
                value={formData.description}
                onChange={handleChange}
                placeholder="Enter description"
                className="mb-3"
              />

              <Button type="submit" className="w-100">
                {loadingSubmit ? "Submitting..." : "Submit Complaint"}
              </Button>

            </Form>
          </Card.Body>
        </Card>

        {/* TABLE */}
        <Card>
          <Card.Header>
            <h5>📜 Complaint History</h5>
          </Card.Header>

          <Card.Body>

            {loadingComplaints ? (
              <Spinner />
            ) : complaints.length === 0 ? (
              <p>No complaints yet</p>
            ) : (
              <Table>
                <thead>
                  <tr>
                    <th>Date</th>
                    <th>Category</th>
                    <th>Subject</th>
                    <th>Status</th>
                  </tr>
                </thead>

                <tbody>
                  {complaints.map(c => (
                    <tr key={c._id}>
                      <td>{new Date(c.createdAt).toLocaleDateString()}</td>
                      <td>{c.category}</td>
                      <td>{c.subject}</td>
                      <td>{getStatusBadge(c.status)}</td>
                    </tr>
                  ))}
                </tbody>
              </Table>
            )}

          </Card.Body>
        </Card>

      </Container>
    </>
  );
};

export default StudentComplaint;